// Pull and normalize lead data
const b = $input.item.json.body;

if (!b.email) throw new Error('Email is required');

const lead = {
  name:    (b.name    || 'Unknown').trim(),
  company: (b.company || 'Unknown').trim(),
  email:   (b.email   || '').trim(),
  role:    (b.role    || 'Not specified').trim(),
  budget:  (b.budget  || 'Not specified').trim(),
  message: (b.message || 'No message provided').trim(),
  source:  (b.source  || 'Website form').trim(),
  submittedAt: new Date().toLocaleString('en-PK', {
    timeZone: 'Asia/Karachi',
    dateStyle: 'medium',
    timeStyle: 'short'
  })
};

// Build the AI prompt
const prompt = `You are an expert B2B sales lead qualifier.

Analyze the following lead and respond with ONLY a valid JSON object — no explanation, no markdown, no extra text.

Lead Information:
- Name: ${lead.name}
- Company: ${lead.company}
- Role/Title: ${lead.role}
- Budget: ${lead.budget}
- Message: ${lead.message}
- Source: ${lead.source}

Respond with exactly this JSON structure:
{
  "score": <number 1-10>,
  "label": <"Hot" or "Warm" or "Cold">,
  "action": <specific recommended next action as a string>,
  "reason": <one sentence explaining the score>
}

Scoring guide:
- Hot (8-10): Decision maker, clear budget, urgent need, specific ask
- Warm (5-7): Interested but vague budget or not decision maker
- Cold (1-4): No budget, student, no company, generic inquiry`;

return { lead, prompt };

// Parse OpenAI response
const raw = $input.item.json.choices?.[0]?.message?.content || '{}';

let ai;
try {
  // Strip any accidental markdown fences
  const clean = raw.replace(/```json|```/g, '').trim();
  ai = JSON.parse(clean);
} catch(e) {
  // Fallback if AI response is malformed
  ai = {
    score: 1,
    label: 'Cold',
    action: 'Review manually — AI parsing failed',
    reason: 'Could not parse AI response'
  };
}

// Get lead data from earlier node
const lead = $('Prepare Lead + Prompt').item.json.lead;

return {
  // Lead fields
  name:        lead.name,
  company:     lead.company,
  email:       lead.email,
  role:        lead.role,
  budget:      lead.budget,
  message:     lead.message,
  source:      lead.source,
  submittedAt: lead.submittedAt,

  // AI qualification
  score:       ai.score,
  label:       ai.label,
  action:      ai.action,
  reason:      ai.reason
};

